// Package checks defines the language-agnostic check protocol used by
// `ddx ac` and (in a later slice) the execute-bead pre_merge gate.
//
// A check is an executable described by a YAML file under .ddx/checks/.
// The runner invokes the executable with a documented set of environment
// variables, then reads a JSON Result document the check writes to
// $EVIDENCE_DIR/<name>.json.
//
// JSON contract (written by check, consumed by runner):
//
//	{
//	  "name": "<check-name>",                 // required, must equal Check.Name
//	  "status": "pass" | "block" | "error",  // required
//	  "summary": "human-readable line",
//	  "violations": [
//	    { "path": "src/foo.go", "line": 42, "message": "..." }
//	  ],
//	  "duration_ms": 123
//	}
//
// Environment variables passed by the runner:
//
//	BEAD_ID       — the bead being checked (may be empty for ad-hoc runs)
//	DIFF_BASE     — git rev for the "before" tree
//	DIFF_HEAD     — git rev for the "after" tree (typically current HEAD)
//	PROJECT_ROOT  — absolute path to the repo root
//	EVIDENCE_DIR  — absolute path to the per-run evidence directory
//	RUN_ID        — identifier for the current ac/pre_merge invocation
//
// Failure modes (all surface as Status=error):
//   - non-zero exit code from the check binary
//   - missing $EVIDENCE_DIR/<name>.json after the check exits
//   - malformed JSON in the result file
//   - timeout (when TimeoutSec is set and exceeded)
package checks

// Status is the verdict a check returns. Block fails the gate; error indicates
// the check itself could not produce a verdict and also fails the gate.
type Status string

const (
	StatusPass  Status = "pass"
	StatusBlock Status = "block"
	StatusError Status = "error"
)

// AppliesTo restricts when a check runs. An empty AppliesTo means "always run".
// Paths and Labels are OR-combined with each other; within each list, any
// match is sufficient (any-of semantics).
type AppliesTo struct {
	// Paths is a list of doublestar glob patterns matched against the set of
	// changed files between DIFF_BASE and DIFF_HEAD. If non-empty, the check
	// runs only when at least one changed file matches at least one pattern.
	Paths []string `yaml:"paths,omitempty"`
	// Labels is a list of bead labels. If non-empty, the check runs only
	// when the bead carries at least one of these labels.
	Labels []string `yaml:"labels,omitempty"`
}

// Check is the in-memory representation of a single .ddx/checks/<name>.yaml
// document.
type Check struct {
	Name        string    `yaml:"name"`
	Description string    `yaml:"description,omitempty"`
	// Command is the argv to execute. The first element is the program;
	// the rest are arguments. The check is invoked from PROJECT_ROOT.
	Command     []string  `yaml:"command"`
	AppliesTo   AppliesTo `yaml:"applies_to,omitempty"`
	// TimeoutSec, when > 0, kills the check after this many seconds and
	// records Status=error.
	TimeoutSec  int       `yaml:"timeout_sec,omitempty"`

	// SourceFile is the path to the YAML file this Check was loaded from.
	// Populated by the loader; ignored on YAML round-trip.
	SourceFile string `yaml:"-"`
}

// Violation is a single finding inside a Result.
type Violation struct {
	Path    string `json:"path,omitempty"`
	Line    int    `json:"line,omitempty"`
	Message string `json:"message"`
}

// Result is the verdict produced by a single check.
type Result struct {
	Name       string      `json:"name"`
	Status     Status      `json:"status"`
	Summary    string      `json:"summary,omitempty"`
	Violations []Violation `json:"violations,omitempty"`

	// Runner-populated fields (not written by the check):
	ExitCode   int    `json:"exit_code,omitempty"`
	Stderr     string `json:"stderr,omitempty"`
	DurationMs int64  `json:"duration_ms,omitempty"`
	// Error is set when the runner could not obtain a verdict (timeout,
	// missing result file, non-zero exit). When non-empty, Status is forced
	// to StatusError.
	Error string `json:"error,omitempty"`
}

package checks

import (
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"

	"gopkg.in/yaml.v3"
)

// LoadDir reads all *.yaml and *.yml files in dir as Check definitions.
// Files are loaded in lexicographic order. The dir itself need not exist;
// a missing directory yields an empty result with no error.
//
// Errors from individual files include the file path and YAML line number
// where available (file:line: message). Unknown YAML fields are rejected.
func LoadDir(dir string) ([]Check, error) {
	entries, err := os.ReadDir(dir)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, fmt.Errorf("read checks dir %s: %w", dir, err)
	}

	var paths []string
	for _, e := range entries {
		if e.IsDir() {
			continue
		}
		name := e.Name()
		if !strings.HasSuffix(name, ".yaml") && !strings.HasSuffix(name, ".yml") {
			continue
		}
		paths = append(paths, filepath.Join(dir, name))
	}
	sort.Strings(paths)

	var out []Check
	seen := make(map[string]string) // name -> source file
	for _, p := range paths {
		c, err := LoadFile(p)
		if err != nil {
			return nil, err
		}
		if prev, ok := seen[c.Name]; ok {
			return nil, fmt.Errorf("%s: duplicate check name %q (also defined in %s)", p, c.Name, prev)
		}
		seen[c.Name] = p
		out = append(out, c)
	}
	return out, nil
}

// LoadFile reads a single YAML file and returns the Check it defines.
func LoadFile(path string) (Check, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return Check{}, fmt.Errorf("%s: %w", path, err)
	}

	dec := yaml.NewDecoder(strings.NewReader(string(data)))
	dec.KnownFields(true)
	var c Check
	if err := dec.Decode(&c); err != nil {
		return Check{}, fmt.Errorf("%s: %w", path, formatYAMLError(path, err))
	}
	c.SourceFile = path
	if err := validateCheck(c); err != nil {
		return Check{}, fmt.Errorf("%s: %w", path, err)
	}
	return c, nil
}

func validateCheck(c Check) error {
	if strings.TrimSpace(c.Name) == "" {
		return fmt.Errorf("missing required field: name")
	}
	if len(c.Command) == 0 {
		return fmt.Errorf("missing required field: command (must be a non-empty list)")
	}
	for i, arg := range c.Command {
		if arg == "" {
			return fmt.Errorf("command[%d] is empty", i)
		}
	}
	if c.TimeoutSec < 0 {
		return fmt.Errorf("timeout_sec must be >= 0, got %d", c.TimeoutSec)
	}
	// Reject names that would be unsafe as filenames (used for evidence path).
	if strings.ContainsAny(c.Name, "/\\") {
		return fmt.Errorf("name %q must not contain path separators", c.Name)
	}
	return nil
}

// formatYAMLError preserves the file:line prefix that yaml.v3 already includes
// in *yaml.TypeError-style messages. We just wrap so callers see a consistent
// shape.
func formatYAMLError(_ string, err error) error {
	return err
}

package checks

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"sync"
	"time"
)

// InvocationContext is the per-run context handed to the runner. It is also
// used by Applies() to filter which checks should run.
type InvocationContext struct {
	BeadID       string
	DiffBase     string
	DiffHead     string
	ProjectRoot  string
	EvidenceDir  string
	RunID        string
	ChangedFiles []string // forward-slash repo-relative paths
	Labels       []string // bead labels for AppliesTo.Labels matching
}

// Applies reports whether the check should run given the invocation context.
// Empty AppliesTo means "always". Otherwise the check runs if any of the
// configured selectors match (Paths OR Labels).
func Applies(c Check, ictx InvocationContext) bool {
	if len(c.AppliesTo.Paths) == 0 && len(c.AppliesTo.Labels) == 0 {
		return true
	}
	if matchAnyLabel(c.AppliesTo.Labels, ictx.Labels) {
		return true
	}
	if matchAnyPath(c.AppliesTo.Paths, ictx.ChangedFiles) {
		return true
	}
	return false
}

func matchAnyLabel(want, have []string) bool {
	if len(want) == 0 {
		return false
	}
	set := make(map[string]struct{}, len(have))
	for _, l := range have {
		set[l] = struct{}{}
	}
	for _, w := range want {
		if _, ok := set[w]; ok {
			return true
		}
	}
	return false
}

func matchAnyPath(patterns, files []string) bool {
	if len(patterns) == 0 {
		return false
	}
	for _, pat := range patterns {
		for _, f := range files {
			if globMatch(pat, f) {
				return true
			}
		}
	}
	return false
}

// globMatch implements a minimal doublestar matcher:
//   - `*`  matches any run of characters except `/`
//   - `**` matches any run of characters including `/`
//   - `?`  matches any single character except `/`
//
// All other characters match literally. Patterns and paths use forward slash.
func globMatch(pattern, name string) bool {
	return globMatchRunes([]rune(pattern), []rune(name))
}

func globMatchRunes(p, n []rune) bool {
	for len(p) > 0 {
		switch p[0] {
		case '*':
			// Detect `**`.
			if len(p) > 1 && p[1] == '*' {
				rest := p[2:]
				// Trim a single trailing `/` from the doublestar wildcard
				// so `a/**/b` matches `a/b` as well as `a/x/b`.
				if len(rest) > 0 && rest[0] == '/' {
					if globMatchRunes(rest[1:], n) {
						return true
					}
				}
				// `**` consumes 0..len(n) runes, including separators.
				for i := 0; i <= len(n); i++ {
					if globMatchRunes(rest, n[i:]) {
						return true
					}
				}
				return false
			}
			rest := p[1:]
			// `*` consumes 0..n runes up to next `/`.
			for i := 0; i <= len(n); i++ {
				if i > 0 && n[i-1] == '/' {
					return false
				}
				if globMatchRunes(rest, n[i:]) {
					return true
				}
			}
			return false
		case '?':
			if len(n) == 0 || n[0] == '/' {
				return false
			}
			p = p[1:]
			n = n[1:]
		default:
			if len(n) == 0 || n[0] != p[0] {
				return false
			}
			p = p[1:]
			n = n[1:]
		}
	}
	return len(n) == 0
}

// Run executes every check whose AppliesTo matches ictx in parallel and
// returns one Result per executed check, in the order checks were given.
// Skipped checks produce no Result.
//
// The runner ensures EvidenceDir exists before invoking checks.
func Run(ctx context.Context, checks []Check, ictx InvocationContext) ([]Result, error) {
	if ictx.EvidenceDir == "" {
		return nil, fmt.Errorf("EvidenceDir is required")
	}
	if err := os.MkdirAll(ictx.EvidenceDir, 0o755); err != nil {
		return nil, fmt.Errorf("create evidence dir: %w", err)
	}

	type job struct {
		idx int
		c   Check
	}
	var jobs []job
	for i, c := range checks {
		if Applies(c, ictx) {
			jobs = append(jobs, job{i, c})
		}
	}

	results := make([]Result, len(jobs))
	var wg sync.WaitGroup
	for i, j := range jobs {
		wg.Add(1)
		go func(slot int, j job) {
			defer wg.Done()
			results[slot] = runOne(ctx, j.c, ictx)
		}(i, j)
	}
	wg.Wait()
	return results, nil
}

func runOne(ctx context.Context, c Check, ictx InvocationContext) Result {
	res := Result{Name: c.Name, Status: StatusError}
	resultPath := filepath.Join(ictx.EvidenceDir, c.Name+".json")
	// Pre-clean any stale result file so we can detect a missing one as error.
	_ = os.Remove(resultPath)

	runCtx := ctx
	var cancel context.CancelFunc
	if c.TimeoutSec > 0 {
		runCtx, cancel = context.WithTimeout(ctx, time.Duration(c.TimeoutSec)*time.Second)
		defer cancel()
	}

	start := time.Now()
	cmd := exec.CommandContext(runCtx, c.Command[0], c.Command[1:]...)
	cmd.Dir = ictx.ProjectRoot
	cmd.Env = append(os.Environ(),
		"BEAD_ID="+ictx.BeadID,
		"DIFF_BASE="+ictx.DiffBase,
		"DIFF_HEAD="+ictx.DiffHead,
		"PROJECT_ROOT="+ictx.ProjectRoot,
		"EVIDENCE_DIR="+ictx.EvidenceDir,
		"RUN_ID="+ictx.RunID,
		"CHECK_NAME="+c.Name,
		"CHECK_RESULT_FILE="+resultPath,
	)
	var stderr strings.Builder
	cmd.Stderr = &stderr
	err := cmd.Run()
	res.DurationMs = time.Since(start).Milliseconds()
	res.Stderr = stderr.String()

	if err != nil {
		if runCtx.Err() == context.DeadlineExceeded {
			res.Error = fmt.Sprintf("timeout after %ds", c.TimeoutSec)
			return res
		}
		if ee, ok := err.(*exec.ExitError); ok {
			res.ExitCode = ee.ExitCode()
			res.Error = fmt.Sprintf("check exited %d", ee.ExitCode())
			return res
		}
		res.Error = err.Error()
		return res
	}

	data, readErr := os.ReadFile(resultPath)
	if readErr != nil {
		res.Error = fmt.Sprintf("missing result file %s", resultPath)
		return res
	}
	var parsed Result
	if err := json.Unmarshal(data, &parsed); err != nil {
		res.Error = fmt.Sprintf("malformed result JSON: %v", err)
		return res
	}
	if parsed.Name != "" && parsed.Name != c.Name {
		res.Error = fmt.Sprintf("result.name %q does not match check name %q", parsed.Name, c.Name)
		return res
	}
	switch parsed.Status {
	case StatusPass, StatusBlock, StatusError:
	default:
		res.Error = fmt.Sprintf("invalid status %q (want pass|block|error)", parsed.Status)
		return res
	}
	parsed.Name = c.Name
	parsed.Stderr = res.Stderr
	parsed.DurationMs = res.DurationMs
	return parsed
}

package checks

import (
	"os"
	"path/filepath"
	"strings"
	"testing"
)

func TestLoadDir_MissingDirIsEmpty(t *testing.T) {
	got, err := LoadDir(filepath.Join(t.TempDir(), "does-not-exist"))
	if err != nil {
		t.Fatalf("LoadDir on missing dir: %v", err)
	}
	if len(got) != 0 {
		t.Fatalf("expected empty result, got %d", len(got))
	}
}

func TestLoadDir_ValidYAMLs(t *testing.T) {
	dir := t.TempDir()
	writeFile(t, dir, "a.yaml", `
name: a
description: first
command: ["true"]
applies_to:
  paths: ["**/*.go"]
  labels: ["area:checks"]
timeout_sec: 5
`)
	writeFile(t, dir, "b.yml", `
name: b
command: ["echo", "ok"]
`)
	// Non-yaml ignored.
	writeFile(t, dir, "README.md", "ignore me")

	got, err := LoadDir(dir)
	if err != nil {
		t.Fatalf("LoadDir: %v", err)
	}
	if len(got) != 2 {
		t.Fatalf("want 2 checks, got %d", len(got))
	}
	if got[0].Name != "a" || got[1].Name != "b" {
		t.Fatalf("unexpected order/names: %+v", got)
	}
	if got[0].TimeoutSec != 5 || got[0].AppliesTo.Paths[0] != "**/*.go" {
		t.Fatalf("missing parsed fields: %+v", got[0])
	}
	if got[0].SourceFile == "" {
		t.Fatalf("SourceFile not populated")
	}
}

func TestLoadFile_UnknownFieldRejected(t *testing.T) {
	dir := t.TempDir()
	path := writeFile(t, dir, "bad.yaml", `
name: bad
command: ["true"]
unknown_field: 1
`)
	_, err := LoadFile(path)
	if err == nil {
		t.Fatal("expected error for unknown field, got nil")
	}
	if !strings.Contains(err.Error(), "bad.yaml") {
		t.Errorf("error should reference file name: %v", err)
	}
	if !strings.Contains(err.Error(), "line") {
		t.Errorf("yaml error should reference line number: %v", err)
	}
}

func TestLoadFile_BadYAMLSyntax(t *testing.T) {
	dir := t.TempDir()
	path := writeFile(t, dir, "broken.yaml", "name: [unterminated\n")
	_, err := LoadFile(path)
	if err == nil {
		t.Fatal("expected parse error")
	}
	if !strings.Contains(err.Error(), "broken.yaml") {
		t.Errorf("error should reference file name: %v", err)
	}
}

func TestLoadFile_MissingRequiredFields(t *testing.T) {
	cases := map[string]string{
		"no name":    `command: ["true"]`,
		"no command": `name: x`,
		"empty arg":  "name: x\ncommand: [\"\"]",
		"bad name":   "name: \"a/b\"\ncommand: [\"true\"]",
		"neg timeout": "name: x\ncommand: [\"true\"]\ntimeout_sec: -1",
	}
	dir := t.TempDir()
	for label, body := range cases {
		t.Run(label, func(t *testing.T) {
			path := writeFile(t, dir, strings.ReplaceAll(label, " ", "_")+".yaml", body)
			if _, err := LoadFile(path); err == nil {
				t.Fatal("expected validation error")
			}
		})
	}
}

func TestLoadDir_DuplicateName(t *testing.T) {
	dir := t.TempDir()
	writeFile(t, dir, "1.yaml", "name: dup\ncommand: [true]\n")
	writeFile(t, dir, "2.yaml", "name: dup\ncommand: [true]\n")
	_, err := LoadDir(dir)
	if err == nil || !strings.Contains(err.Error(), "duplicate") {
		t.Fatalf("expected duplicate-name error, got %v", err)
	}
}

func writeFile(t *testing.T, dir, name, body string) string {
	t.Helper()
	p := filepath.Join(dir, name)
	if err := os.WriteFile(p, []byte(body), 0o644); err != nil {
		t.Fatal(err)
	}
	return p
}

