		{
			name: "doublestar middle",
			c:    Check{AppliesTo: AppliesTo{Paths: []string{"a/**/b.go"}}},
			ictx: InvocationContext{ChangedFiles: []string{"a/x/y/b.go"}},
			want: true,
		},
		{
			name: "doublestar collapses to no dirs",
			c:    Check{AppliesTo: AppliesTo{Paths: []string{"a/**/b.go"}}},
			ictx: InvocationContext{ChangedFiles: []string{"a/b.go"}},
			want: true,
		},
		{
			name: "non-matching paths and matching label still runs",
			c: Check{AppliesTo: AppliesTo{
				Paths:  []string{"docs/**"},
				Labels: []string{"area:checks"},
			}},
			ictx: InvocationContext{
				ChangedFiles: []string{"src/main.go"},
				Labels:       []string{"area:checks"},
			},
			want: true,
		},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			if got := Applies(tc.c, tc.ictx); got != tc.want {
				t.Fatalf("Applies = %v, want %v", got, tc.want)
			}
		})
	}
}

