func TestRunner_ParallelExecution(t *testing.T) {
	if runtime.GOOS == "windows" {
		t.Skip("POSIX shell")
	}
	dir := t.TempDir()
	script := writeScript(t, dir, "sleep.sh", `#!/bin/sh
sleep 0.3
cat > "$CHECK_RESULT_FILE" <<EOF
{"name":"$CHECK_NAME","status":"pass"}
EOF
`)
	checks := []Check{
		{Name: "p1", Command: []string{script}},
		{Name: "p2", Command: []string{script}},
		{Name: "p3", Command: []string{script}},
	}
	start := time.Now()
	res, err := Run(context.Background(), checks, InvocationContext{
		ProjectRoot: dir,
		EvidenceDir: filepath.Join(dir, "ev"),
	})
	if err != nil {
		t.Fatalf("Run: %v", err)
	}
	elapsed := time.Since(start)
	if len(res) != 3 {
		t.Fatalf("want 3 results, got %d", len(res))
	}
	// Serial would take ~0.9s; parallel should finish well under 0.7s.
	if elapsed > 700*time.Millisecond {
		t.Fatalf("checks did not run in parallel: elapsed=%s", elapsed)
	}
	for _, r := range res {
		if r.Status != StatusPass {
			t.Fatalf("non-pass result: %+v", r)
		}
	}
}

