package cmd

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/checks"
	"github.com/spf13/cobra"
)

func (f *CommandFactory) newAcCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "ac",
		Short: "Acceptance checks: run check-protocol checks against the worktree",
		Long: `Run language-agnostic acceptance checks defined under .ddx/checks/.

Each check is an executable described by a YAML file. The runner invokes the
check with BEAD_ID, DIFF_BASE, DIFF_HEAD, PROJECT_ROOT, EVIDENCE_DIR, and
RUN_ID in the environment, then reads a JSON result from
$EVIDENCE_DIR/<check-name>.json.

Exit codes:
  0  all checks passed
  1  one or more checks returned status=block or status=error
  2  internal/configuration error`,
	}
	cmd.AddCommand(f.newAcRunCommand())
	return cmd
}

func (f *CommandFactory) newAcRunCommand() *cobra.Command {
	c := &cobra.Command{
		Use:   "run <bead-id>",
		Short: "Run all applicable checks against the current worktree for a bead",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			beadID := args[0]
			only, _ := cmd.Flags().GetString("check")
			asJSON, _ := cmd.Flags().GetBool("json")

			workspace := f.beadWorkspaceRoot()
			if workspace == "" {
				return fmt.Errorf("not inside a DDx workspace; run 'ddx init' first")
			}

			s := f.beadStore()
			b, err := s.Get(beadID)
			if err != nil {
				return fmt.Errorf("loading bead %s: %w", beadID, err)
			}

			diffBase, err := resolveDiffBase(workspace, b)
			if err != nil {
				return fmt.Errorf("resolve diff base: %w", err)
			}
			diffHead, err := gitOutput(workspace, "rev-parse", "HEAD")
			if err != nil {
				return fmt.Errorf("resolve HEAD: %w", err)
			}
			changed, err := gitChangedFiles(workspace, diffBase, diffHead)
			if err != nil {
				return fmt.Errorf("compute changed files: %w", err)
			}

			loaded, err := checks.LoadDir(filepath.Join(workspace, ".ddx", "checks"))
			if err != nil {
				return err
			}
			if only != "" {
				filtered := loaded[:0]
				for _, ck := range loaded {
					if ck.Name == only {
						filtered = append(filtered, ck)
					}
				}
				loaded = filtered
				if len(loaded) == 0 {
					return fmt.Errorf("no check named %q under .ddx/checks/", only)
				}
			}

			runID := "ac-" + time.Now().UTC().Format("20060102T150405Z")
			evidenceDir := filepath.Join(workspace, ".ddx", "executions", runID)

			ictx := checks.InvocationContext{
				BeadID:       b.ID,
				DiffBase:     diffBase,
				DiffHead:     diffHead,
				ProjectRoot:  workspace,
				EvidenceDir:  evidenceDir,
				RunID:        runID,
				ChangedFiles: changed,
				Labels:       b.Labels,
			}

			results, err := checks.Run(context.Background(), loaded, ictx)
			if err != nil {
				return err
			}

			out := cmd.OutOrStdout()
			if asJSON {
				enc := json.NewEncoder(out)
				enc.SetIndent("", "  ")
				if err := enc.Encode(results); err != nil {
					return err
				}
			} else {
				fmt.Fprintf(out, "bead:     %s\n", b.ID)
				fmt.Fprintf(out, "diff:     %s..%s\n", shortRev(diffBase), shortRev(diffHead))
				fmt.Fprintf(out, "evidence: %s\n", evidenceDir)
				if len(results) == 0 {
					fmt.Fprintln(out, "(no applicable checks)")
				}
				for _, r := range results {
					fmt.Fprintf(out, "  %-8s %s", strings.ToUpper(string(r.Status)), r.Name)
					if r.Summary != "" {
						fmt.Fprintf(out, " — %s", r.Summary)
					}
					if r.Error != "" {
						fmt.Fprintf(out, " (%s)", r.Error)
					}
					fmt.Fprintln(out)
					for _, v := range r.Violations {
						loc := v.Path
						if v.Line > 0 {
							loc = fmt.Sprintf("%s:%d", v.Path, v.Line)
						}
						fmt.Fprintf(out, "      %s %s\n", loc, v.Message)
					}
				}
			}

			for _, r := range results {
				if r.Status == checks.StatusBlock || r.Status == checks.StatusError {
					os.Exit(1)
				}
			}
			return nil
		},
	}
	c.Flags().String("check", "", "Run only the named check")
	c.Flags().Bool("json", false, "Emit results as JSON")
	return c
}

// resolveDiffBase consults the bead's Extra map for a "base-rev" hint, then
// falls back to the merge-base with origin/main, then HEAD~1, then HEAD.
func resolveDiffBase(workdir string, b *bead.Bead) (string, error) {
	if v, ok := b.Extra["base-rev"].(string); ok && v != "" {
		if rev, err := gitOutput(workdir, "rev-parse", "--verify", v); err == nil {
			return rev, nil
		}
	}
	for _, ref := range []string{"origin/main", "main", "origin/master", "master"} {
		if rev, err := gitOutput(workdir, "merge-base", "HEAD", ref); err == nil && rev != "" {
			return rev, nil
		}
	}
	if rev, err := gitOutput(workdir, "rev-parse", "HEAD~1"); err == nil {
		return rev, nil
	}
	return gitOutput(workdir, "rev-parse", "HEAD")
}

func gitChangedFiles(workdir, base, head string) ([]string, error) {
	out, err := gitOutput(workdir, "diff", "--name-only", base, head)
	if err != nil {
		return nil, err
	}
	if out == "" {
		return nil, nil
	}
	lines := strings.Split(out, "\n")
	files := make([]string, 0, len(lines))
	for _, l := range lines {
		if l = strings.TrimSpace(l); l != "" {
			files = append(files, filepath.ToSlash(l))
		}
	}
	return files, nil
}

func gitOutput(workdir string, args ...string) (string, error) {
	cmd := exec.Command("git", args...)
	cmd.Dir = workdir
	out, err := cmd.Output()
	if err != nil {
		return "", err
	}
	return strings.TrimSpace(string(out)), nil
}

func shortRev(s string) string {
	if len(s) > 12 {
		return s[:12]
	}
	return s
}
